package com.ghatana.audit.integrity.domain;

import lombok.Builder;
import lombok.Value;

import java.time.Instant;
import java.util.List;

/**
 * Report generated by audit integrity verification job
 * Day 42: Audit Integrity - Verification Reporting
 */
@Value
@Builder
public class AuditIntegrityReport {
    
    /**
     * Unique identifier for this integrity report
     */
    String reportId;
    
    /**
     * Timestamp when verification was performed
     */
    Instant verificationTime;
    
    /**
     * Starting timestamp of audit data verified
     */
    Instant auditStartTime;
    
    /**
     * Ending timestamp of audit data verified
     */
    Instant auditEndTime;
    
    /**
     * Total number of audit batches verified
     */
    long totalBatches;
    
    /**
     * Total number of audit entries verified
     */
    long totalEntries;
    
    /**
     * Number of batches that passed verification
     */
    long verifiedBatches;
    
    /**
     * Number of batches with integrity issues
     */
    long tamperedBatches;
    
    /**
     * Number of missing batches in the chain
     */
    long missingBatches;
    
    /**
     * List of batch IDs with integrity violations
     */
    List<String> violationBatchIds;
    
    /**
     * List of detected integrity violations
     */
    List<IntegrityViolation> violations;
    
    /**
     * Overall integrity status
     */
    IntegrityStatus overallStatus;
    
    /**
     * Time taken to complete verification in milliseconds
     */
    long verificationDurationMs;
    
    /**
     * Calculate integrity score as percentage
     */
    public double getIntegrityScore() {
        if (totalBatches == 0) {
            return 100.0;
        }
        return (double) verifiedBatches / totalBatches * 100.0;
    }
    
    /**
     * Check if integrity verification passed
     */
    public boolean isIntegrityPassed() {
        return overallStatus == IntegrityStatus.VERIFIED && violations.isEmpty();
    }
    
    /**
     * Overall integrity status
     */
    public enum IntegrityStatus {
        VERIFIED,
        COMPROMISED,
        PARTIAL_FAILURE,
        VERIFICATION_ERROR
    }
    
    /**
     * Represents a specific integrity violation
     */
    @Value
    @Builder
    public static class IntegrityViolation {
        String batchId;
        ViolationType violationType;
        String description;
        String expectedValue;
        String actualValue;
        Instant detectedAt;
        
        public enum ViolationType {
            HASH_MISMATCH,
            MISSING_BATCH,
            BROKEN_CHAIN,
            TAMPERED_ENTRY,
            SEQUENCE_GAP
        }
    }
}